member.example:
Bind the MeshCollider sharedMesh property using a serialized binder field — the target MeshCollider is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private MeshColliderMeshBinder _mesh;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public Mesh _mesh;
    }


Bind the MeshCollider sharedMesh property by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private MeshCollider _meshCollider;
        
        private MeshColliderMeshBinder Mesh =>
            new(_meshCollider);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public Mesh _mesh;
    }

Switch the MeshCollider sharedMesh between two Mesh assets using a serialized binder field — the target MeshCollider is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private MeshColliderMeshSwitcherBinder _isActive;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isActive;
    }


Switch the MeshCollider sharedMesh between two Mesh assets by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private MeshCollider _meshCollider;
        [SerializeField] private Mesh _activeMesh;
        [SerializeField] private Mesh _inactiveMesh;
        
        private MeshColliderMeshSwitcherBinder IsActive => new(
            _meshCollider,
            trueValue: _activeMesh,
            falseValue: _inactiveMesh);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isActive;
    }
